    const indiceAleatorio = Math.floor(Math.random() * palabrasAleatorias.length);
    return palabrasAleatorias[indiceAleatorio];
}

// Función para crear el array de palabra oculta con guiones
function crearPalabraOculta(palabra) {
    return Array(palabra.length).fill("_");
}

// Función para inicializar el juego
function inicializarJuego() {
    palabraSeleccionada = seleccionarPalabraAleatoria();
    palabraOculta = crearPalabraOculta(palabraSeleccionada);
    intentosRestantes = 6;
    letrasUsadas = [];

    console.log("¡Bienvenido al Juego del Ahorcado!");
    console.log(`La palabra tiene ${palabraSeleccionada.length} letras`);
    mostrarEstadoJuego();
}

