    console.log(`Letras usadas: ${letrasUsadas.join(", ") || "Ninguna"}`);
    console.log("=".repeat(40) + "\n");
}

// Función para verificar si la letra está en la palabra
function verificarLetra(letra) {
    letra = letra.toLowerCase();

    // Validar que sea una sola letra
    if (letra.length !== 1 || !/[a-z]/.test(letra)) {
        console.log("❌ Por favor, ingresa solo una letra válida.");
        return false;
    }

    // Verificar si la letra ya fue usada
    if (letrasUsadas.includes(letra)) {
        console.log("⚠️ Ya usaste esa letra. Intenta con otra.");
        return false;
    }

    // Agregar letra a las usadas
    letrasUsadas.push(letra);

    // Verificar si la letra está en la palabra
    let letraEncontrada = false;

    for (let i = 0; i < palabraSeleccionada.length; i++) {
        if (palabraSeleccionada[i] === letra) {
