        }
    }

    if (letraEncontrada) {
        console.log(`✅ ¡Correcto! La letra "${letra}" está en la palabra.`);
    } else {
        intentosRestantes--;
        console.log(`❌ La letra "${letra}" no está en la palabra.`);
        dibujarAhorcado();
    }

    return true;
}

