    <h1>Juego del Ahorcado</h1>
    <p>Adivina la palabra ingresando una letra a la vez.</p>

    <!-- Aquí se mostrarán los guiones y las letras acertadas -->
    <div id="palabra-oculta"></div>

    <input type="text" id="letra-ingresada" maxlength="1" placeholder="a">
