        // 1. Crear un array de palabras aleatorias a adivinar
        const palabras = ["javascript", "programacion", "computadora", "teclado", "desarrollador", "internet"];

        // 2. Escoger una palabra aleatoria del array
        const palabraSeleccionada = palabras[Math.floor(Math.random() * palabras.length)];

        // 3. Crear el arreglo "palabrasOcultas" y reemplazar con guiones
        let palabrasOcultas = [];
        for (let i = 0; i < palabraSeleccionada.length; i++) {
            palabrasOcultas.push("_"); // Usamos guión bajo para representar las letras ocultas
        }

