gemini.text:
As a Google Ads specialist and JavaScript expert, I have designed a modern, efficient Google Ads script to identify Negative Keyword Conflicts. 

A conflict occurs when you are actively bidding on a keyword, but a negative keyword (at either the Campaign or Ad Group level) is blocking it from triggering ads. This script systematically checks your active keywords against your negative keywords and logs any conflicts it finds into a Google Spreadsheet for easy review.

### The Google Ads Script

```javascript
/**
 * Google Ads Script: Negative Keyword Conflict Checker
 * 
 * This script scans all enabled campaigns and ad groups to find active biddable 
 * keywords that are being blocked by your own negative keywords.
 * 
 * Outputs the results to a specified Google Sheet.
 */

const CONFIG = {
  // Insert the URL of an empty Google Sheet here
  SPREADSHEET_URL: 'YOUR_SPREADSHEET_URL_HERE', 
  CAMPAIGN_NAME_CONTAINS: '', // Optional: Filter by campaign name (leave empty for all)
};

function main() {
  Logger.log('Starting Negative Keyword Conflict Checker...');

  const conflicts = [];

  // 1. Fetch all enabled campaigns
  let campaignSelector = AdsApp.campaigns().withCondition("Status = ENABLED");
  if (CONFIG.CAMPAIGN_NAME_CONTAINS) {
    campaignSelector = campaignSelector.withCondition(`Name CONTAINS_IGNORE_CASE '${CONFIG.CAMPAIGN_NAME_CONTAINS}'`);
  }

  const campaignIterator = campaignSelector.get();

  while (campaignIterator.hasNext()) {
    const campaign = campaignIterator.next();
    const campaignName = campaign.getName();

    // 2. Get Campaign-level negative keywords
    const campaignNegatives = getNegativeKeywords(campaign.negativeKeywords().get());

    // 3. Iterate through enabled Ad Groups in this campaign
    const adGroupIterator = campaign.adGroups().withCondition("Status = ENABLED").get();

    while (adGroupIterator.hasNext()) {
      const adGroup = adGroupIterator.next();
      const adGroupName = adGroup.getName();

      // 4. Get Ad Group-level negative keywords
      const adGroupNegatives = getNegativeKeywords(adGroup.negativeKeywords().get());

      // Combine campaign and ad group negatives
      const allNegatives = [...campaignNegatives, ...adGroupNegatives];
      if (allNegatives.length === 0) continue;

      // 5. Get active biddable keywords
      const keywordIterator = adGroup.keywords().withCondition("Status = ENABLED").get();

      while (keywordIterator.hasNext()) {
        const keyword = keywordIterator.next();
        const keywordText = keyword.getText().toLowerCase();

        // 6. Check for conflicts
        const conflictingNegative = findConflict(keywordText, allNegatives);

        if (conflictingNegative) {
          conflicts.push([
            campaignName,
            adGroupName,
            keyword.getText(),
            keyword.getMatchType(),
            conflictingNegative.text,
            conflictingNegative.matchType,
            conflictingNegative.level
          ]);
        }
      }
    }
  }

  // 7. Output results
  outputToSpreadsheet(conflicts);
}

/**
 * Helper function to extract negative keywords from an iterator
 */
function getNegativeKeywords(iterator) {
  const negatives = [];
  while (iterator.hasNext()) {
    const neg = iterator.next();
    negatives.push({
      text: neg.getText().toLowerCase(),
      matchType: neg.getMatchType(),
      // Determine level based on the entity type (Campaign vs AdGroup)
      level: neg.getEntityType() === 'CampaignNegativeKeyword' ? 'Campaign' : 'AdGroup'
    });
  }
  return negatives;
}

/**
 * Core Logic: Checks if a positive keyword is blocked by any negative keyword
 */
function findConflict(positiveText, negatives) {
  // Clean the positive text for accurate matching
  const cleanPosText = positiveText.replace(/[\[\]"']/g, '');
  const posWords = cleanPosText.split(' ');

  for (const neg of negatives) {
    const cleanNegText = neg.text.replace(/[\[\]"']/g, '');

    switch (neg.matchType) {
      case 'EXACT':
        // Exact match negative blocks only if the text is exactly the same
        if (cleanPosText === cleanNegText) return neg;
        break;

      case 'PHRASE':
        // Phrase match negative blocks if the exact phrase is contained within the keyword
        // We add spaces around the strings to prevent partial word matches (e.g., "cat" matching "caterpillar")
        if (` ${cleanPosText} `.includes(` ${cleanNegText} `)) return neg;
        break;

      case 'BROAD':
        // Broad match negative blocks if ALL words in the negative keyword are present in the positive keyword, in any order
        const negWords = cleanNegText.split(' ');
        const isBroadConflict = negWords.every(word => posWords.includes(word));
        if (isBroadConflict) return neg;
        break;
    }
  }
  return null; // No conflict found
}

/**
 * Exports the findings to a Google Sheet
 */
function outputToSpreadsheet(conflicts) {
  if (CONFIG.SPREADSHEET_URL === 'YOUR_SPREADSHEET_URL_HERE') {
    Logger.log('WARNING: Please add a valid Google Sheet URL to the CONFIG object.');
    Logger.log(`Found ${conflicts.length} conflicts. Check logs for details.`);
    conflicts.forEach(c => Logger.log(`Conflict: Keyword [${c[2]}] blocked by Negative [${c[4]}]`));
    return;
  }

  const spreadsheet = SpreadsheetApp.openByUrl(CONFIG.SPREADSHEET_URL);
  const sheet = spreadsheet.getActiveSheet();

  // Clear previous data
  sheet.clear();

  // Set Headers
  const headers = ['Campaign', 'Ad Group', 'Positive Keyword', 'Pos. Match Type', 'Conflicting Negative', 'Neg. Match Type', 'Negative Level'];
  sheet.appendRow(headers);

  // Format Headers
  sheet.getRange(1, 1, 1, headers.length).setFontWeight('bold').setBackground('#f3f3f3');

  // Append Data
  if (conflicts.length > 0) {
    sheet.getRange(2, 1, conflicts.length, headers.length).setValues(conflicts);
    Logger.log(`Successfully exported ${conflicts.length} conflicts to the spreadsheet.`);
  } else {
    sheet.appendRow(['No conflicts found!', '', '', '', '', '', '']);
    Logger.log('Great news! No negative keyword conflicts were found.');
  }
}
```

### Explanation of the Script & Development Steps

Here is the step-by-step process I took to develop this script, utilizing modern JavaScript principles (ES6+) supported by the new Google Ads Scripts V8 engine:

#### 1. Structuring the Configuration
I started by creating a `CONFIG` object. Using a constant object for configuration is a modern JS best practice. It keeps hardcoded variables (like the Spreadsheet URL) at the very top of the script so users don't have to dig through the code to make changes.

#### 2. Iterating Through the Account Hierarchy
Google Ads is structured hierarchically. To find conflicts, the script must traverse this structure:
*   **Campaigns:** I used `AdsApp.campaigns()` to fetch active campaigns.
*   **Ad Groups:** Inside the campaign loop, I fetched active ad groups.
*   **Keywords:** Inside the ad group loop, I fetched active biddable keywords.

#### 3. Gathering Negative Keywords
A keyword can be blocked by a negative keyword at either the Campaign level or the Ad Group level. 
*   I created a helper function `getNegativeKeywords()` to extract the text, match type, and level of the negatives. 
*   I used the ES6 spread operator (`[...campaignNegatives, ...adGroupNegatives]`) to elegantly combine both arrays into a single list of negatives to check against.

#### 4. The Core Conflict Logic (`findConflict` function)
This is the most complex part of the script. Google Ads negative match types behave differently than positive match types (they do not expand to synonyms). I implemented the exact logic Google uses:
*   **Exact Match (`EXACT`):** The negative keyword only blocks the positive keyword if they are identical.
*   **Phrase Match (`PHRASE`):** The negative keyword blocks the positive keyword if the positive keyword contains the exact phrase. I used template literals and the `.includes()` method, padding the strings with spaces (` ${cleanPosText} `) to ensure we match whole words (so a negative for "car" doesn't accidentally block "carpet").
*   **Broad Match (`BROAD`):** A broad negative blocks a keyword if *all* words in the negative keyword are present in the positive keyword, regardless of order. I used the modern JS array methods `.split()`, `.every()`, and `.includes()` to check if every word in the negative array exists in the positive array.

#### 5. Outputting to Google Sheets
Logging data to the console is fine for a few items, but for large accounts, a spreadsheet is necessary. 
*   I used `SpreadsheetApp` to open a user-provided URL.
*   The script clears the sheet on every run so you don't get duplicate old data.
*   It uses `.setValues()` to write all data in a single batch operation. Batch operations are significantly faster and more efficient than writing rows one by one in a loop.

### How to Use This Script
1. Create a new, blank Google Sheet and copy its URL.
2. In your Google Ads account, go to **Tools & Settings > Scripts**.
3. Click the **+** button to add a new script.
4. Paste the code above into the editor.
5. Replace `'YOUR_SPREADSHEET_URL_HERE'` on line 12 with your actual Google Sheet URL.
6. Click **Preview** to authorize the script and test it, then click **Run** or set it on a weekly schedule.

