### 1. CLARIFY
The objective is to develop a Google Ads Script in JavaScript that identifies "Negative Keyword Conflicts." A conflict occurs when a positive keyword in a campaign or ad group is inadvertently blocked by a negative keyword in the same scope. The script needs to evaluate match types (Exact, Phrase, Broad) to accurately determine if a negative keyword suppresses a positive one.

### 2. APPROACH
To solve this, we need to compare positive keywords against negative keywords within the same scope (e.g., Campaign). 

*   **Approach 1: Brute Force Comparison (Nested Loops)**
    Iterate through every positive keyword. For each, iterate through every negative keyword in the same campaign and check for a match based on the negative keyword's match type. 
    *Time Complexity*: $O(P \times N)$ where $P$ is the number of positive keywords and $N$ is the number of negative keywords.
    *Space Complexity*: $O(1)$ beyond the storage of the keywords.

*   **Approach 2: Pre-processed Hash Maps and Regex (Optimal)**
    Group negative keywords by campaign. Pre-process Exact match negatives into a `Set` for $O(1)$ lookups. Pre-process Phrase match negatives into Regular Expressions (to ensure word boundary matching), and Broad match negatives into arrays of required words. Then, iterate through positive keywords and check against the optimized negative structures for their specific campaign.
    *Time Complexity*: $O(P \times N_{pb} + P)$ where $N_{pb}$ is the number of phrase/broad negative keywords per campaign. Exact matches are checked in $O(1)$.
    *Space Complexity*: $O(N)$ to store the optimized negative keyword structures.

We will proceed with **Approach 2** as it significantly reduces the overhead of string comparisons, especially for Exact matches, which are common in large accounts.

### 3 & 4. CODE IMPLEMENTATION

Here is the core algorithmic logic, followed by the Google Ads Script wrapper.

```javascript
/**
 * Core Algorithm: Finds conflicts between positive and negative keywords.
 * 
 * @param {Array} positiveKeywords - Array of { text, matchType, campaign }
 * @param {Array} negativeKeywords - Array of { text, matchType, campaign }
 * @returns {Array} List of conflicts { positive, negative }
 */
function findNegativeKeywordConflicts(positiveKeywords, negativeKeywords) {
    const conflicts = [];

    // Pre-process negative keywords by campaign for optimized lookups
    const negativesByCampaign = {};

    for (const neg of negativeKeywords) {
        if (!negativesByCampaign[neg.campaign]) {
            negativesByCampaign[neg.campaign] = {
                exact: new Set(),
                phrase: [],
                broad: []
            };
        }

        const cleanText = neg.text.toLowerCase();
        if (neg.matchType === 'EXACT') {
            negativesByCampaign[neg.campaign].exact.add(cleanText);
        } else if (neg.matchType === 'PHRASE') {
            // Use regex to ensure word boundaries (e.g., "shoe" doesn't block "shoes")
            const escaped = cleanText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
            negativesByCampaign[neg.campaign].phrase.push({
                original: neg,
                regex: new RegExp(`\\b${escaped}\\b`, 'i')
            });
        } else if (neg.matchType === 'BROAD') {
            negativesByCampaign[neg.campaign].broad.push({
                original: neg,
                words: cleanText.split(/\s+/)
            });
        }
    }

    // Evaluate positive keywords against pre-processed negatives
    for (const pos of positiveKeywords) {
        const campaignNegatives = negativesByCampaign[pos.campaign];
        if (!campaignNegatives) continue;

        const posText = pos.text.toLowerCase();
        let conflictFound = false;

        // 1. Check Exact Match Negatives O(1)
        if (campaignNegatives.exact.has(posText)) {
            conflicts.push({ positive: pos, negative: { text: posText, matchType: 'EXACT', campaign: pos.campaign } });
            continue;
        }

        // 2. Check Phrase Match Negatives O(N_phrase)
        for (const negPhrase of campaignNegatives.phrase) {
            if (negPhrase.regex.test(posText)) {
                conflicts.push({ positive: pos, negative: negPhrase.original });
                conflictFound = true;
                break;
            }
        }
        if (conflictFound) continue;

        // 3. Check Broad Match Negatives O(N_broad * W)
        for (const negBroad of campaignNegatives.broad) {
            // For broad negative, EVERY word in the negative keyword must be present in the positive keyword
            const posWords = new Set(posText.split(/\s+/));
            const isBlocked = negBroad.words.every(word => posWords.has(word));

            if (isBlocked) {
                conflicts.push({ positive: pos, negative: negBroad.original });
                break;
            }
        }
    }

    return conflicts;
}

