if (typeof process !== 'undefined' && process.release.name === 'node') {
    // 1. Create a standard BoxGeometry
    const geometry = new THREE.BoxGeometry(1, 1, 1);

    // 2. Check initial UV of the first vertex (usually 0 or 1)
    console.log("Before:", geometry.attributes.uv.getX(0), geometry.attributes.uv.getY(0)); 

    // 3. Apply a texture repeat of (4, 2)
    bakeRepeatIntoUVs(geometry, 4, 2);

    // 4. Verify the UVs have been scaled
    console.log("After:", geometry.attributes.uv.getX(0), geometry.attributes.uv.getY(0));
    // Expected Output: Scaled values based on the initial UVs (e.g., if initial was 1, 1 -> now 4, 2)
}
```

