# CLARIFY
This React component manages video URL input (YouTube, Vimeo, Loom), validates URLs, toggles YouTube privacy mode, and handles add/remove actions. Key issues: excessive state management, unclear separation of concerns, redundant logic, and tight coupling between UI and business logic.

---

# REFACTORING SUGGESTIONS

## 1. **Extract Business Logic into Custom Hook**
Move all video URL logic (validation, parsing, privacy mode) into a `useVideoUrl` hook. This separates concerns and makes testing easier.

```typescript
// hooks/useVideoUrl.ts
import { useState, useCallback } from "react";
import { toast } from "react-hot-toast";
import {
  checkForYoutubePrivacyMode,
  checkForYoutubeUrl,
  extractYoutubeId,
  parseVideoUrl,
} from "../lib/utils";

const SUPPORTED_PLATFORMS = [
  "youtube.com",
  "youtu.be",
  "youtube-nocookie.com",
  "vimeo.com",
  "loom.com",
] as const;

export const useVideoUrl = (
  initialUrl: string,
  onFileUpload: (urls: string[] | undefined, fileType: "image" | "video") => void
) => {
  const [url, setUrl] = useState(initialUrl);
  const [isYoutubeLink, setIsYoutubeLink] = useState(checkForYoutubeUrl(initialUrl));
  const [isPrivacyMode, setIsPrivacyMode] = useState(checkForYoutubePrivacyMode(initialUrl));

  const isSupportedPlatform = useCallback((videoUrl: string) => {
    return SUPPORTED_PLATFORMS.some((domain) => videoUrl.includes(domain));
  }, []);

  const handleUrlChange = useCallback((newUrl: string) => {
    setUrl(newUrl);
    setIsYoutubeLink(checkForYoutubeUrl(newUrl));
    setIsPrivacyMode(checkForYoutubePrivacyMode(newUrl));
  }, []);

  const togglePrivacyMode = useCallback(() => {
    const videoId = extractYoutubeId(url);
    if (!videoId) {
      toast.error("Invalid YouTube URL");
      return;
    }

    const newUrl = isPrivacyMode
      ? `https://www.youtube.com/embed/${videoId}`
      : `https://www.youtube-nocookie.com/embed/${videoId}`;

    setUrl(newUrl);
    setIsPrivacyMode(!isPrivacyMode);
    onFileUpload([newUrl], "video");
  }, [url, isPrivacyMode, onFileUpload]);

  const addVideo = useCallback(() => {
    const parsedUrl = parseVideoUrl(url);
    if (parsedUrl) {
      setUrl(parsedUrl);
      onFileUpload([parsedUrl], "video");
      return true;
    }
    toast.error("URL not supported");
    return false;
  }, [url, onFileUpload]);

  const removeVideo = useCallback(() => {
    setUrl("");
    onFileUpload([], "video");
  }, [onFileUpload]);

  return {
    url,
    isYoutubeLink,
    isPrivacyMode,
    isSupportedPlatform: isSupportedPlatform(url),
    handleUrlChange,
    togglePrivacyMode,
    addVideo,
    removeVideo,
  };
};
