Here is a complete implementation using the `postgres` npm package (often referred to as `postgres.js`). 

This script connects to the database, fetches the schema from `information_schema.columns`, and uses an asynchronous cursor to stream the rows of an arbitrary table directly to a writable stream (like `process.stdout` or an HTTP response) as a single, properly formatted JSON object.

### Prerequisites
First, install the package:
```bash
npm install postgres
```

### Implementation

```javascript
const postgres = require('postgres');

// 1. Connect to the PostgreSQL database
// Replace with your actual connection string
const sql = postgres('postgres://username:password@localhost:5432/database_name');

/**
 * Streams the schema and data of an arbitrary table as JSON.
 * 
 * @param {string} tableName - The name of the table to query.
 * @param {WritableStream} outputStream - The Node.js writable stream (e.g., process.stdout, HTTP response).
 */
async function streamTableDataAsJson(tableName, outputStream) {
  try {
    // 2. Enumerate the table's schema
    // We query the information_schema to get column details for the arbitrary table
    const schema = await sql`
      SELECT 
        column_name, 
        data_type, 
        is_nullable, 
        character_maximum_length
      FROM information_schema.columns
      WHERE table_name = ${ tableName }
      ORDER BY ordinal_position;
    `;

    if (schema.length === 0) {
      throw new Error(`Table "${tableName}" does not exist or has no columns.`);
    }

    // Start writing the JSON structure to the output stream
    outputStream.write('{\n');
    outputStream.write(`  "table": "${tableName}",\n`);

    // Write the schema array
    const schemaJson = JSON.stringify(schema, null, 2).split('\n').join('\n  ');
    outputStream.write(`  "schema": ${schemaJson},\n`);

    // Open the data array
    outputStream.write('  "data": [\n');

    // 3. Run SELECT * and stream the results
    let isFirstRow = true;

    // We use sql(tableName) to safely escape the arbitrary table name and prevent SQL injection.
    // .cursor(100) fetches rows in batches of 100, preventing memory overload on large tables.
    for await (const rows of sql`SELECT * FROM ${ sql(tableName) }`.cursor(100)) {
      for (const row of rows) {
        // Handle comma placement for valid JSON array syntax
        const prefix = isFirstRow ? '    ' : ',\n    ';

        // Write the row directly to the stream
        outputStream.write(prefix + JSON.stringify(row));
        isFirstRow = false;
      }
    }

    // Close the data array and the main JSON object
    outputStream.write('\n  ]\n}\n');

  } catch (err) {
    console.error('Error streaming table data:', err);
  } finally {
    // Clean up the database connection
    await sql.end();
  }
}

// ==========================================
// Example Usage
// ==========================================

// Stream the results of the 'users' table directly to the console
streamTableDataAsJson('users', process.stdout)
  .then(() => console.log('\nStreaming complete.'))
  .catch(console.error);
```

### Key features of this implementation:
1. **Safe Dynamic Identifiers:** By using `${ sql(tableName) }` in the `SELECT *` query, the `postgres` package safely escapes the table name, protecting you from SQL injection (which is a common risk when querying arbitrary tables).
2. **Memory Efficiency:** Instead of loading the entire table into memory with a standard `await sql...`, it uses `.cursor(100)`. This creates an async iterable that fetches rows in chunks of 100, allowing you to stream tables with millions of rows without running out of RAM.
3. **Manual JSON Chunking:** Because standard `JSON.stringify()` requires the entire object to be in memory, this script manually writes the JSON brackets `{}`, `[]`, and commas to the stream, inserting the stringified schema and rows exactly where they belong.

