Below is a minimal, self-contained Node.js program that does exactly what you asked:

- connects to Postgres with the `postgres` package  
- runs `SELECT * FROM <table>`  
- runs a second query that enumerates the table’s schema (column names, data types, nullability, defaults, etc.)  
- streams both result sets back to the caller as newline-delimited JSON (ND-JSON) so you can pipe the output or consume it incrementally

Save the file as `pg-stream.js`, install the dependency (`npm i postgres`), and run:

```bash
node pg-stream.js postgres://user:pass@localhost:5432/mydb mytable
```

Code:

```js
#!/usr/bin/env node
/**
 * pg-stream.js
 *
 * Usage:
 *   node pg-stream.js <connection-url> <table>
 *
 * Example:
 *   node pg-stream.js postgres://user:pass@localhost:5432/dbname users
 *
 * Output:
 *   {"type":"schema","columns":[...]}
 *   {"type":"row","row":{...}}
 *   {"type":"row","row":{...}}
 *   ...
 *   {"type":"end"}
 */

import postgres from 'postgres';
import { Writable } from 'stream';

const [, , CONNECTION_URL, TABLE_NAME] = process.argv;

if (!CONNECTION_URL || !TABLE_NAME) {
  console.error('Usage: node pg-stream.js <connection-url> <table>');
  process.exit(1);
}

// Create an SQL tagged-template literal function
const sql = postgres(CONNECTION_URL);

// A tiny writable stream that just writes JSON + newline to stdout
const out = new Writable({
  objectMode: true,
  write(chunk, _enc, cb) {
    process.stdout.write(JSON.stringify(chunk) + '\n', cb);
  },
});

// Helper to stream a query result directly into `out`
async function streamQuery(queryPromise, label) {
  const stream = queryPromise.stream();
  for await (const row of stream) {
    out.write({ type: label, row });
  }
}

(async () => {
  try {
    // 1. Emit schema
    const schemaRows = await sql`
      SELECT
        column_name      AS name,
        data_type        AS type,
        is_nullable      AS nullable,
        column_default   AS default_value
      FROM information_schema.columns
      WHERE table_name = ${TABLE_NAME}
      ORDER BY ordinal_position
    `;
    out.write({ type: 'schema', columns: schemaRows });

    // 2. Stream all rows
    await streamQuery(sql`SELECT * FROM ${sql(TABLE_NAME)}`, 'row');

    // 3. Signal end
    out.write({ type: 'end' });
  } catch (err) {
    console.error('ERROR:', err);
    process.exitCode = 1;
  } finally {
    await sql.end();
  }
})();
```

Notes
1. The script uses the official `postgres` package’s `stream()` helper, which yields rows as they arrive—perfect for large tables.  
2. Each emitted object has a `type` field so downstream consumers can distinguish schema from rows from the end marker.  
3. If you want to stream to something other than stdout, replace the `out` Writable with your own destination (e.g., an HTTP response, file, etc.).

