		return nil, err
	}
	return resp.LoadBalancerDescriptions, nil
}

func countIPsFromDNS(dnsName string) int {
	ips, err := net.LookupIP(dnsName)
	if err != nil {
		return 0
	}
	return len(ips)
}
func populateTableWithLB(table *tview.Table, lb elbv2types.LoadBalancer, row int) {
	// Extract necessary information from lb
	lbArn := *lb.LoadBalancerArn
	lbType := string(lb.Type)
	dnsName := *lb.DNSName
	ipCount := countIPsFromDNS(dnsName)

	// Populate the table
	table.SetCell(row, 0, tview.NewTableCell(lbArn))
	table.SetCell(row, 1, tview.NewTableCell(lbType))
	table.SetCell(row, 2, tview.NewTableCell(dnsName))
	table.SetCell(row, 3, tview.NewTableCell(strconv.Itoa(ipCount))) // Convert int to string
}

func populateTableWithClassicLB(table *tview.Table, lb elbtypes.LoadBalancerDescription, row int) {
	// Extract necessary information from lb
	lbName := *lb.LoadBalancerName
	dnsName := *lb.DNSName
	ipCount := countIPsFromDNS(dnsName)

	// Populate the table
	table.SetCell(row, 0, tview.NewTableCell(lbName))
	table.SetCell(row, 1, tview.NewTableCell("classic")) // Classic ELB doesn't have a type in its description
	table.SetCell(row, 2, tview.NewTableCell(dnsName))
	table.SetCell(row, 3, tview.NewTableCell(strconv.Itoa(ipCount))) // Convert int to string
}

func createAndPopulateLBTable(client *elbv2.Client, classicClient *elb.Client) *tview.Table {
	table := tview.NewTable().SetBorders(true)
	// ... Set headers ...

	lbs, _ := fetchLoadBalancers(client)
	classicLbs, _ := fetchClassicLoadBalancers(classicClient)

	row := 1
	for _, lb := range lbs {
		populateTableWithLB(table, lb, row)
		row++
	}

	for _, lb := range classicLbs {
		populateTableWithClassicLB(table, lb, row)
		row++
	}

	return table
}

